sys_script_fix.script:
var BASE_URL = gs.getProperty('glide.servlet.uri');

  var cars = [
      { name: 'Beta 1',     chassi: 'DLGY1RD5B5QMCOIZF' },
      { name: 'Iota 54',    chassi: '5O2ERWRV3ZQD24KEL' },
      { name: 'Epsilon 2',  chassi: 'L6DO2VKIW0NJOXJVH' },
      { name: 'Alpha 33',   chassi: 'UCHNVSWRWJ8OS41P6' },
      { name: 'Beta 45',    chassi: 'W1V34345XYR73TGNJ' },
      { name: 'Theta 84',   chassi: '80VUA5W5TL1XFYY63' },
      { name: 'Gamma 48',   chassi: 'JTM663XEXY8YSGCPO' },
      { name: 'Epsilon 96', chassi: 'HI6RZBK6DD4LACVGU' },
      { name: 'Beta 95',    chassi: 'TFLXKG89HPKXPVIIV' },
      { name: 'Alpha 42',   chassi: '93HVCAPEVQIGEB3OX' }
  ];

  var log = function(m) { gs.info('[ChainCatalog] ' + m); };
  var created = 0, skipped = 0;

  for (var i = 0; i < cars.length; i++) {
      var c = cars[i];

      var existing = new GlideRecord('x_1880990_chain_car_catalog');
      existing.addQuery('car_chassi', c.chassi);
      existing.query();
      if (existing.next()) {
          skipped++;  
          log('skip: ' + c.name);
          continue;
      }

      var rec = new GlideRecord('x_1880990_chain_car_catalog');
      rec.initialize();
      rec.car_name = c.name;
      rec.car_chassi = c.chassi;
      rec.image_url = BASE_URL + c.chassi + '.png';
      rec.active = true;
      var id = rec.insert();
      if (id) {
          created++;
          log('created: ' + c.name + ' -> ' + c.chassi);
      } else {
          gs.error('[ChainCatalog] FAILED: ' + c.name);
      }
  }

  log('=== Total criados: ' + created + ', skipped: ' + skipped + ' ===');
